3728 static std::optional<ModRefInfo>
3729 isAllocSiteRemovable(Instruction *AI, SmallVectorImpl<WeakTrackingVH> &Users,
3730                      const TargetLibraryInfo &TLI, bool KnowInit) {
3731   SmallVector<Instruction*, 4> Worklist;
3732   const std::optional<StringRef> Family = getAllocationFamily(AI, &TLI);
3733   Worklist.push_back(AI);
3734   ModRefInfo Access = KnowInit ? ModRefInfo::NoModRef : ModRefInfo::Mod;
3735 
3736   do {
3737     Instruction *PI = Worklist.pop_back_val();
3738     for (User *U : PI->users()) {
3739       Instruction *I = cast<Instruction>(U);
3740       switch (I->getOpcode()) {
3741       default:
3742         // Give up the moment we see something we can't handle.
3743         return std::nullopt;
3744 
3745       case Instruction::AddrSpaceCast:
3746       case Instruction::BitCast:
3747       case Instruction::GetElementPtr:
3748         Users.emplace_back(I);
3749         Worklist.push_back(I);
3750         continue;
3751 
3752       case Instruction::ICmp: {
3753         ICmpInst *ICI = cast<ICmpInst>(I);
3754         // We can fold eq/ne comparisons with null to false/true, respectively.
3755         // We also fold comparisons in some conditions provided the alloc has
3756         // not escaped (see isNeverEqualToUnescapedAlloc).
3757         if (!ICI->isEquality())
3758           return std::nullopt;
3759         unsigned OtherIndex = (ICI->getOperand(0) == PI) ? 1 : 0;
3760         if (!isNeverEqualToUnescapedAlloc(ICI->getOperand(OtherIndex), TLI, AI))
3761           return std::nullopt;
3762 
3763         // Do not fold compares to aligned_alloc calls, as they may have to
3764         // return null in case the required alignment cannot be satisfied,
3765         // unless we can prove that both alignment and size are valid.
3766         auto AlignmentAndSizeKnownValid = [](CallBase *CB) {
3767           // Check if alignment and size of a call to aligned_alloc is valid,
3768           // that is alignment is a power-of-2 and the size is a multiple of the
3769           // alignment.
3770           const APInt *Alignment;
3771           const APInt *Size;
3772           return match(CB->getArgOperand(0), m_APInt(Alignment)) &&
3773                  match(CB->getArgOperand(1), m_APInt(Size)) &&
3774                  Alignment->isPowerOf2() && Size->urem(*Alignment).isZero();
3775         };
3776         auto *CB = dyn_cast<CallBase>(AI);
3777         LibFunc TheLibFunc;
3778         if (CB && TLI.getLibFunc(*CB->getCalledFunction(), TheLibFunc) &&
3779             TLI.has(TheLibFunc) && TheLibFunc == LibFunc_aligned_alloc &&
3780             !AlignmentAndSizeKnownValid(CB))
3781           return std::nullopt;
3782         Users.emplace_back(I);
3783         continue;
3784       }
3785 
3786       case Instruction::Call:
3787         // Ignore no-op and store intrinsics.
3788         if (IntrinsicInst *II = dyn_cast<IntrinsicInst>(I)) {
3789           switch (II->getIntrinsicID()) {
3790           default:
3791             return std::nullopt;
3792 
3793           case Intrinsic::memmove:
3794           case Intrinsic::memcpy:
3795           case Intrinsic::memset: {
3796             MemIntrinsic *MI = cast<MemIntrinsic>(II);
3797             if (MI->isVolatile())
3798               return std::nullopt;
