3800             // as just Mod in that case.
3801             ModRefInfo NewAccess =
3802                 MI->getRawDest() == PI ? ModRefInfo::Mod : ModRefInfo::Ref;
3803             if ((Access & ~NewAccess) != ModRefInfo::NoModRef)
3804               return std::nullopt;
3805             Access |= NewAccess;
3806             [[fallthrough]];
3807           }
3808           case Intrinsic::assume:
3809           case Intrinsic::invariant_start:
3810           case Intrinsic::invariant_end:
3811           case Intrinsic::lifetime_start:
3812           case Intrinsic::lifetime_end:
3813           case Intrinsic::objectsize:
3814             Users.emplace_back(I);
3815             continue;
3816           case Intrinsic::launder_invariant_group:
3817           case Intrinsic::strip_invariant_group:
3818             Users.emplace_back(I);
3819             Worklist.push_back(I);
3820             continue;
3821           }
3822         }
3823 
3824         if (Family && getFreedOperand(cast<CallBase>(I), &TLI) == PI &&
3825             getAllocationFamily(I, &TLI) == Family) {
