3827           continue;
3828         }
3829 
3830         if (Family && getReallocatedOperand(cast<CallBase>(I)) == PI &&
3831             getAllocationFamily(I, &TLI) == Family) {
3832           Users.emplace_back(I);
3833           Worklist.push_back(I);
3834           continue;
3835         }
3836 
